        return;
    }

    let min = *arr.iter().min().unwrap();
    let mut offset = 0;

    if min < 0 {
        offset = min.abs();
        for x in arr.iter_mut() {
            *x += offset;
        }
    }

    let max = *arr.iter().max().unwrap();
    let mut exp = 1;

    while max / exp > 0 {
        counting_sort(arr, exp);
        exp *= 10;
